import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"景山公园","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/jingshan.md","filePath":"landmarks/jingshan.md","lastUpdated":null}'),n={name:"landmarks/jingshan.md"};function d(o,t,s,i,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="景山公园" tabindex="-1">景山公园 <a class="header-anchor" href="#景山公园" aria-label="Permalink to &quot;景山公园&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1508804185872-d7badad00f7d?w=1200" alt="景山公园"></p><blockquote><p>&quot;会当凌绝顶，一览众山小。&quot; —— 杜甫《望岳》</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>景山公园位于北京西城区，原为元、明、清三代的皇家御苑。公园中心的景山高42.6米，是北京内城的制高点，登顶可俯瞰整个紫禁城和北京中轴线，是拍摄故宫全景的最佳地点。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">6:00-21:00（旺季），6:30-20:00（淡季）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">2元（北京最便宜的皇家园林）</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">1-2小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">春秋两季，特别是秋季</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">公交58、111、124路景山东街站</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="明代建山" tabindex="-1">明代建山 <a class="header-anchor" href="#明代建山" aria-label="Permalink to &quot;明代建山&quot;">​</a></h3><p>明永乐年间（1406-1420年），修建紫禁城时，将开挖护城河的泥土堆积于此，形成五座山峰，命名为&quot;万岁山&quot;，俗称&quot;煤山&quot;。</p><h3 id="崇祯殉国" tabindex="-1">崇祯殉国 <a class="header-anchor" href="#崇祯殉国" aria-label="Permalink to &quot;崇祯殉国&quot;">​</a></h3><p>1644年，李自成攻破北京，明朝末代皇帝崇祯在景山东麓的歪脖槐树上自缢身亡，标志着明朝的灭亡。</p><h2 id="主要景点" tabindex="-1">主要景点 <a class="header-anchor" href="#主要景点" aria-label="Permalink to &quot;主要景点&quot;">​</a></h2><h3 id="万春亭-主峰" tabindex="-1">万春亭（主峰） <a class="header-anchor" href="#万春亭-主峰" aria-label="Permalink to &quot;万春亭（主峰）&quot;">​</a></h3><p>位于景山主峰，是俯瞰紫禁城的最佳观景点。</p><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>海拔</strong></td><td style="text-align:left;">88.7米</td></tr><tr><td style="text-align:left;"><strong>建筑</strong></td><td style="text-align:left;">三重檐四角攒尖顶</td></tr><tr><td style="text-align:left;"><strong>视野</strong></td><td style="text-align:left;">360度俯瞰北京城</td></tr></tbody></table><p><img src="https://images.unsplash.com/photo-1599661046289-e31897846e41?w=800" alt="故宫全景"></p><p>站在万春亭，向南可俯瞰故宫全景，向北可望见鼓楼，向西可远眺西山。</p><h3 id="崇祯皇帝殉国处" tabindex="-1">崇祯皇帝殉国处 <a class="header-anchor" href="#崇祯皇帝殉国处" aria-label="Permalink to &quot;崇祯皇帝殉国处&quot;">​</a></h3><p>位于景山东麓，石碑上刻有&quot;明思宗殉国处&quot;。原树已枯死，现存为后来补植。</p><h3 id="五方亭" tabindex="-1">五方亭 <a class="header-anchor" href="#五方亭" aria-label="Permalink to &quot;五方亭&quot;">​</a></h3><p>景山五座山峰上各建有一座亭子，代表五行，守护着紫禁城。</p><h2 id="文化故事" tabindex="-1">文化故事 <a class="header-anchor" href="#文化故事" aria-label="Permalink to &quot;文化故事&quot;">​</a></h2><h3 id="崇祯殉国-1" tabindex="-1">崇祯殉国 <a class="header-anchor" href="#崇祯殉国-1" aria-label="Permalink to &quot;崇祯殉国&quot;">​</a></h3><p>1644年3月19日，崇祯皇帝在衣襟上留下遗诏：&quot;朕凉德藐躬，上干天咎，然皆诸臣误朕。朕死无面目见祖宗，自去冠冕，以发覆面。任贼分裂，无伤百姓一人。&quot;随后在景山自缢。</p><h3 id="景山与紫禁城的风水" tabindex="-1">景山与紫禁城的风水 <a class="header-anchor" href="#景山与紫禁城的风水" aria-label="Permalink to &quot;景山与紫禁城的风水&quot;">​</a></h3><p>景山位于紫禁城正北，在风水上称为&quot;靠山&quot;，有&quot;前有水（金水河），后有山（景山）&quot;之意。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="最佳游览时间" tabindex="-1">最佳游览时间 <a class="header-anchor" href="#最佳游览时间" aria-label="Permalink to &quot;最佳游览时间&quot;">​</a></h3><ul><li><strong>日出</strong>：拍摄故宫晨曦</li><li><strong>上午</strong>：光线适合拍照</li><li><strong>傍晚</strong>：拍摄故宫日落</li><li><strong>夜景</strong>：周五、周六及节假日故宫夜景</li></ul><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>快速观光（1小时）</strong>： 南门 → 绮望楼 → 登万春亭 → 俯瞰故宫 → 崇祯殉国处 → 出园</p><h3 id="摄影指南" tabindex="-1">摄影指南 <a class="header-anchor" href="#摄影指南" aria-label="Permalink to &quot;摄影指南&quot;">​</a></h3><p><strong>最佳拍摄点</strong>：</p><ol><li><strong>万春亭</strong>：故宫全景、中轴线</li><li><strong>半山腰平台</strong>：故宫特写</li><li><strong>后山</strong>：寿皇殿与天空</li></ol><h3 id="四季特色" tabindex="-1">四季特色 <a class="header-anchor" href="#四季特色" aria-label="Permalink to &quot;四季特色&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">季节</th><th style="text-align:left;">特色</th><th style="text-align:left;">看点</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>春季</strong></td><td style="text-align:left;">牡丹花展</td><td style="text-align:left;">数百种牡丹盛开</td></tr><tr><td style="text-align:left;"><strong>夏季</strong></td><td style="text-align:left;">绿树成荫</td><td style="text-align:left;">避暑纳凉</td></tr><tr><td style="text-align:left;"><strong>秋季</strong></td><td style="text-align:left;">红叶黄叶</td><td style="text-align:left;">色彩斑斓</td></tr><tr><td style="text-align:left;"><strong>冬季</strong></td><td style="text-align:left;">雪后故宫</td><td style="text-align:left;">银装素裹</td></tr></tbody></table><h2 id="交通指南" tabindex="-1">交通指南 <a class="header-anchor" href="#交通指南" aria-label="Permalink to &quot;交通指南&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">入口</th><th style="text-align:left;">交通方式</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>南门</strong></td><td style="text-align:left;">公交58、111、124路景山东街站（近故宫神武门）</td></tr><tr><td style="text-align:left;"><strong>东门</strong></td><td style="text-align:left;">近北海公园</td></tr><tr><td style="text-align:left;"><strong>西门</strong></td><td style="text-align:left;">公交5路西板桥站</td></tr></tbody></table><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th></tr></thead><tbody><tr><td style="text-align:left;">故宫</td><td style="text-align:center;">0米（隔街相望）</td></tr><tr><td style="text-align:left;">北海公园</td><td style="text-align:center;">500米</td></tr><tr><td style="text-align:left;">什刹海</td><td style="text-align:center;">800米</td></tr></tbody></table><hr><p><strong>💡 Tips</strong>：景山公园是北京性价比最高的景点之一，仅需2元门票，就能看到故宫全景。强烈建议作为故宫游览的下一站，从神武门出故宫，直接进入景山公园。</p>',43)])])}const b=e(n,[["render",d]]);export{f as __pageData,b as default};
